// Device Integrity Checker
class DeviceIntegrityChecker(private val context: Context) {
    
    private val securityManager = SecurityManager(context)
    
    suspend fun performIntegrityCheck(): IntegrityResult = withContext(Dispatchers.IO) {
        val checks = mutableListOf<SecurityCheck>()
        
        // Check if device is rooted
        checks.add(SecurityCheck(
            "Root Detection",
            !securityManager.isRooted(),
            if (securityManager.isRooted()) "Device appears to be rooted" else "Device not rooted"
        ))
        
        // Check if running on emulator
        checks.add(SecurityCheck(
            "Emulator Detection",
            !securityManager.checkEmulator(),
            if (securityManager.checkEmulator()) "Running on emulator" else "Running on physical device"
        ))
        
        // Check device security
        checks.add(SecurityCheck(
            "Device Security",
            securityManager.isDeviceSecure(),
            if (securityManager.isDeviceSecure()) "Device has screen lock" else "No screen lock set"
        ))
        
        // Check Google Play Services
        val playServicesAvailable = GoogleApiAvailability.getInstance()
            .isGooglePlayServicesAvailable(context) == ConnectionResult.SUCCESS
        checks.add(SecurityCheck(
            "Play Services",
            playServicesAvailable,
            if (playServicesAvailable) "Google Play Services available" else "Google Play Services unavailable"
        ))
        
        // Check app signature
        val signatureValid = verifyAppSignature()
        checks.add(SecurityCheck(
            "App Signature",
            signatureValid,
            if (signatureValid) "App signature valid" else "App signature invalid"
        ))
        
        val allPassed = checks.all { it.passed }
        IntegrityResult(allPassed, checks)
    }
    
    private fun verifyAppSignature(): Boolean {
        return try {
            val packageInfo = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                context.packageManager.getPackageInfo(
                    context.packageName,
                    android.content.pm.PackageManager.GET_SIGNING_CERTIFICATES
                )
            } else {
                @Suppress("DEPRECATION")
                context.packageManager.getPackageInfo(
                    context.packageName,
                    android.content.pm.PackageManager.GET_SIGNATURES
                )
            }
            
            val signatures = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                packageInfo.signingInfo?.apkContentsSigners
            } else {
                @Suppress("DEPRECATION")
                packageInfo.signatures
            }
            
            signatures?.isNotEmpty() ?: false
        } catch (e: Exception) {
            false
        }
    }
    
    suspend fun performSafetyNetAttestation(apiKey: String): SafetyNetResult = withContext(Dispatchers.IO) {
        try {
            val nonce = generateNonce()
            val result = suspendCancellableCoroutine<SafetyNetResult> { continuation ->
                SafetyNet.getClient(context)
                    .attest(nonce, apiKey)
                    .addOnSuccessListener { response ->
                        continuation.resume(SafetyNetResult(true, response.jwsResult), null)
                    }
                    .addOnFailureListener { e ->
                        continuation.resume(SafetyNetResult(false, e.message ?: "Unknown error"), null)
                    }
            }
            result
        } catch (e: Exception) {
            SafetyNetResult(false, e.message ?: "SafetyNet check failed")
        }
    }
    
    private fun generateNonce(): ByteArray {
        val nonce = ByteArray(32)
        SecureRandom().nextBytes(nonce)
        return nonce
    }
}

