// Payment Processor
class PaymentProcessor(
    private val context: Context,
    private val securityManager: SecurityManager
) {
    
    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())
    
    fun encryptPaymentCard(card: PaymentCard): EncryptedPaymentCard {
        return EncryptedPaymentCard(
            encryptedCardNumber = securityManager.encryptData(card.cardNumber),
            encryptedCvv = securityManager.encryptData(card.cvv),
            expiryMonth = card.expiryMonth,
            expiryYear = card.expiryYear,
            cardHolderName = card.cardHolderName
        )
    }
    
    fun decryptPaymentCard(encryptedCard: EncryptedPaymentCard): PaymentCard {
        return PaymentCard(
            cardNumber = securityManager.decryptData(encryptedCard.encryptedCardNumber),
            cvv = securityManager.decryptData(encryptedCard.encryptedCvv),
            expiryMonth = encryptedCard.expiryMonth,
            expiryYear = encryptedCard.expiryYear,
            cardHolderName = encryptedCard.cardHolderName
        )
    }
    
    suspend fun processPayment(
        card: PaymentCard,
        amount: Double,
        currency: String
    ): PaymentResult = withContext(Dispatchers.IO) {
        try {
            // Validate card
            if (!validateCard(card)) {
                return@withContext PaymentResult.Failed("Invalid card details")
            }
            
            // Encrypt sensitive data
            val encryptedCard = encryptPaymentCard(card)
            
            // Simulate payment processing
            delay(2000)
            
            // Generate transaction ID
            val transactionId = generateTransactionId()
            
            PaymentResult.Success(transactionId, amount, currency)
        } catch (e: Exception) {
            PaymentResult.Failed(e.message ?: "Payment processing failed")
        }
    }
    
    private fun validateCard(card: PaymentCard): Boolean {
        // Luhn algorithm for card number validation
        if (!isValidCardNumber(card.cardNumber)) return false
        
        // Validate expiry
        if (card.expiryMonth < 1 || card.expiryMonth > 12) return false
        if (card.expiryYear < 2024) return false
        
        // Validate CVV
        if (card.cvv.length < 3 || card.cvv.length > 4) return false
        
        return true
    }
    
    private fun isValidCardNumber(cardNumber: String): Boolean {
        val digits = cardNumber.replace(" ", "").filter { it.isDigit() }
        if (digits.length < 13 || digits.length > 19) return false
        
        var sum = 0
        var alternate = false
        
        for (i in digits.length - 1 downTo 0) {
            var digit = digits[i].toString().toInt()
            
            if (alternate) {
                digit *= 2
                if (digit > 9) digit -= 9
            }
            
            sum += digit
            alternate = !alternate
        }
        
        return sum % 10 == 0
    }
    
    private fun generateTransactionId(): String {
        val timestamp = System.currentTimeMillis()
        val random = SecureRandom().nextInt(100000)
        return "TXN${timestamp}${random}"
    }
}

