// Wallet Manager
class WalletManager(
    private val context: Context,
    private val securityManager: SecurityManager
) {
    
    private val walletPrefs = context.getSharedPreferences("wallet_prefs", Context.MODE_PRIVATE)
    private val balanceKey = "wallet_balance"
    
    fun getBalance(): Double {
        val encryptedBalance = walletPrefs.getString(balanceKey, null) ?: return 0.0
        val iv = walletPrefs.getString("${balanceKey}_iv", null) ?: return 0.0
        
        return try {
            val decrypted = securityManager.decryptData(EncryptedData(encryptedBalance, iv))
            decrypted.toDouble()
        } catch (e: Exception) {
            0.0
        }
    }
    
    fun setBalance(balance: Double) {
        val encrypted = securityManager.encryptData(balance.toString())
        walletPrefs.edit()
            .putString(balanceKey, encrypted.data)
            .putString("${balanceKey}_iv", encrypted.iv)
            .apply()
    }
    
    suspend fun addFunds(amount: Double): TransactionResult = withContext(Dispatchers.IO) {
        try {
            if (amount <= 0) {
                return@withContext TransactionResult.Failed("Invalid amount")
            }
            
            val currentBalance = getBalance()
            val newBalance = currentBalance + amount
            setBalance(newBalance)
            
            val transaction = WalletTransaction(
                id = generateTransactionId(),
                amount = amount,
                currency = "USD",
                type = TransactionType.CREDIT,
                timestamp = System.currentTimeMillis(),
                status = TransactionStatus.COMPLETED,
                description = "Funds added to wallet"
            )
            
            saveTransaction(transaction)
            TransactionResult.Success(transaction)
        } catch (e: Exception) {
            TransactionResult.Failed(e.message ?: "Failed to add funds")
        }
    }
    
    suspend fun deductFunds(amount: Double, description: String): TransactionResult = withContext(Dispatchers.IO) {
        try {
            if (amount <= 0) {
                return@withContext TransactionResult.Failed("Invalid amount")
            }
            
            val currentBalance = getBalance()
            if (currentBalance < amount) {
                return@withContext TransactionResult.Failed("Insufficient balance")
            }
            
            val newBalance = currentBalance - amount
            setBalance(newBalance)
            
            val transaction = WalletTransaction(
                id = generateTransactionId(),
                amount = amount,
                currency = "USD",
                type = TransactionType.DEBIT,
                timestamp = System.currentTimeMillis(),
                status = TransactionStatus.COMPLETED,
                description = description
            )
            
            saveTransaction(transaction)
            TransactionResult.Success(transaction)
        } catch (e: Exception) {
            TransactionResult.Failed(e.message ?: "Failed to deduct funds")
        }
    }
    
    fun getTransactionHistory(): List<WalletTransaction> {
        val transactionsJson = walletPrefs.getString("transactions", "[]") ?: "[]"
        // In production, use proper JSON parsing library
        return emptyList()
    }
    
    private fun saveTransaction(transaction: WalletTransaction) {
        // In production, save to secure database
        val transactions = getTransactionHistory().toMutableList()
        transactions.add(transaction)
        // Save back to preferences (encrypted)
    }
    
    private fun generateTransactionId(): String {
        val timestamp = System.currentTimeMillis()
        val random = SecureRandom().nextInt(100000)
        return "WLT${timestamp}${random}"
    }
}

