// Main Payment Module
class PaymentModule(private val context: Context) {
    
    private val securityManager = SecurityManager(context)
    private val deviceIntegrityChecker = DeviceIntegrityChecker(context)
    private val paymentProcessor = PaymentProcessor(context, securityManager)
    private val walletManager = WalletManager(context, securityManager)
    private val inAppPurchaseManager = InAppPurchaseManager(context, securityManager, walletManager)
    
    suspend fun initialize(): InitializationResult {
        return try {
            val integrityResult = deviceIntegrityChecker.performIntegrityCheck()
            
            if (!integrityResult.passed) {
                val failedChecks = integrityResult.checks.filter { !it.passed }
                InitializationResult.SecurityWarning(
                    "Device security checks failed: ${failedChecks.joinToString { it.name }}"
                )
            } else {
                InitializationResult.Success
            }
        } catch (e: Exception) {
            InitializationResult.Failed(e.message ?: "Initialization failed")
        }
    }
    
    fun getPaymentProcessor() = paymentProcessor
    fun getWalletManager() = walletManager
    fun getInAppPurchaseManager() = inAppPurchaseManager
    fun getSecurityManager() = securityManager
    fun getDeviceIntegrityChecker() = deviceIntegrityChecker
    
    suspend fun performSecurityCheck(): IntegrityResult {
        return deviceIntegrityChecker.performIntegrityCheck()
    }
}

sealed class InitializationResult {
    object Success : InitializationResult()
    data class SecurityWarning(val message: String) : InitializationResult()
    data class Failed(val reason: String) : InitializationResult()
}

// Usage Example Activity
class PaymentActivity : FragmentActivity() {
    
    private lateinit var paymentModule: PaymentModule
    private lateinit var biometricAuthManager: BiometricAuthManager
    
    override fun onCreate(savedInstanceState: android.os.Bundle?) {
        super.onCreate(savedInstanceState)
        
        paymentModule = PaymentModule(this)
        biometricAuthManager = BiometricAuthManager(this)
        
        CoroutineScope(Dispatchers.Main).launch {
            initializePaymentModule()
        }
    }
    
    private suspend fun initializePaymentModule() {
        when (val result = paymentModule.initialize()) {
            is InitializationResult.Success -> {
                // Module initialized successfully
                processPaymentWithBiometric()
            }
            is InitializationResult.SecurityWarning -> {
                // Show warning but allow to continue
                android.util.Log.w("PaymentActivity", result.message)
            }
            is InitializationResult.Failed -> {
                // Handle initialization failure
                android.util.Log.e("PaymentActivity", result.reason)
            }
        }
    }
    
    private suspend fun processPaymentWithBiometric() {
        if (biometricAuthManager.canAuthenticate() == BiometricCapability.AVAILABLE) {
            when (biometricAuthManager.authenticate("Payment Authentication", "Confirm your payment")) {
                is BiometricResult.Success -> {
                    processPayment()
                }
                is BiometricResult.Failed -> {
                    // Authentication failed
                }
                is BiometricResult.Error -> {
                    // Authentication error
                }
            }
        } else {
            processPayment()
        }
    }
    
    private suspend fun processPayment() {
        val card = PaymentCard(
            cardNumber = "4532015112830366",
            expiryMonth = 12,
            expiryYear = 2025,
            cvv = "123",
            cardHolderName = "John Doe"
        )
        
        when (val result = paymentModule.getPaymentProcessor().processPayment(card, 99.99, "USD")) {
            is PaymentResult.Success -> {
                // Payment successful
                android.util.Log.d("PaymentActivity", "Payment successful: ${result.transactionId}")
            }
            is PaymentResult.Failed -> {
                // Payment failed
                android.util.Log.e("PaymentActivity", "Payment failed: ${result.reason}")
            }
        }
    }
